/**
 * merge-descriptors
 *
 * Merge objects using property descriptors, preserving getters/setters and property attributes.
 * This module is a critical dependency for Express.js, used during initialization to combine application properties.
 *
 * @param {Object} dest - The destination object to merge properties into
 * @param {Object} src - The source object to merge properties from
 * @param {Boolean} [redefine=false] - Whether to redefine existing properties
 * @return {Object} The destination object
 * @public
 */

module.exports = merge;

/**
 * Merge the property descriptors of `src` into `dest`
 *
 * @param {Object} dest - The destination object
 * @param {Object} src - The source object
 * @param {Boolean} [redefine=false] - Whether to redefine existing properties
 * @return {Object} The destination object
 * @public
 */
function merge(dest, src, redefine) {
  if (!dest) {
    throw new TypeError('argument dest is required');
  }

  if (!src) {
    throw new TypeError('argument src is required');
  }

  if (redefine === undefined) {
    // Default to false
    redefine = false;
  }

  // Get all own property names and symbols from source
  var props = Object.getOwnPropertyNames(src);
  var symbols;
  
  // Check if Symbol is supported in the environment
  if (typeof Object.getOwnPropertySymbols === 'function') {
    symbols = Object.getOwnPropertySymbols(src);
    if (symbols.length) {
      props = props.concat(symbols);
    }
  }

  // Iterate over all properties
  for (var i = 0; i < props.length; i++) {
    var prop = props[i];

    // Skip if property already exists on destination and redefine is false
    if (!redefine && Object.prototype.hasOwnProperty.call(dest, prop)) {
      continue;
    }

    // Get the property descriptor from source
    var descriptor = Object.getOwnPropertyDescriptor(src, prop);

    // Define the property on destination with the same descriptor
    Object.defineProperty(dest, prop, descriptor);
  }

  return dest;
}